SELECT ?work ?workLabel WHERE { 
  wd:Q164974 wdt:P577 ?oliverDate .
  ?work wdt:P50 wd:Q5686 ;
        wdt:P31/wdt:P279* wd:Q1347298 ;
        wdt:P577 ?workDate ;
        rdfs:label ?workLabel .
  FILTER(LANG(?workLabel) = "en") .
  FILTER(YEAR(?workDate) < YEAR(?oliverDate)) .
  FILTER(?work != wd:Q164974)
} ORDER BY DESC(YEAR(?workDate)) LIMIT 1

